function addMonthsToDate(date, mon) {
  // Create a new date object to avoid modifying the original date
  let newDate = new Date(date);  
  // Add the months to the current month of the date
  newDate.setMonth(newDate.getMonth() + parseInt(mon));  
  return newDate;
}

// Function to format date as YYYY-MM-DD HH:MM:SS
function formatDateTime(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  const hh = String(date.getHours()).padStart(2, '0');
  const min = String(date.getMinutes()).padStart(2, '0');
  const ss = String(date.getSeconds()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}:${ss}`;
}

function formatTime(date) {
  return date.toLocaleTimeString('en-US', {
    hour: 'numeric',
    minute: 'numeric',
    second: 'numeric',
    hour12: true,
  });
}

function format_12(timeString){
  if(!timeString){ return ''; }
  let oras = timeString.split(':');
  let hh = oras[0].padStart(2, '0');
  let mm = oras[1].padStart(2, '0');
  let xhh=Number(hh);
  //alert(xhh);
  
  /*
  if(xhh > 12){
    hh=(xhh - 12).toString().padStart(2, '0');
  }
  if(xhh == 0){
    hh=(12).toString().padStart(2, '0');
  }
  */

  //alert("hh:"+hh);
  return hh+':'+mm;
}

function time_AmPm(timeString){
  if(!timeString){ return ''; }
  let oras = timeString.split(':');
  let hh = oras[0].padStart(2, '0');
  let mm = oras[1].padStart(2, '0');
  let xhh=Number(hh);
  let ampm='AM';
  //alert(xhh);
  
  
  if(xhh > 12){
    hh=(xhh - 12).toString().padStart(2, '0');
    ampm='PM';
  }
  if(xhh == 0){
    hh=(12).toString().padStart(2, '0');
  }

  //alert("hh:"+hh);
  return hh+':'+mm+' '+ampm;
}

function JBE_FORMAT_TIME(timeString) {
  if(!timeString){ return ''; }
  // Split the time string into hours and minutes
  var parts = timeString.split(':');

  // Ensure both hours and minutes have leading zeros if necessary
  var hours = parts[0].padStart(2, '0');
  var minutes = parts[1].padStart(2, '0');

  // Return the time with leading zeros
  return hours + ':' + minutes;
} 

